        assert_eq!(result.one_tick_input.retry_attempts_used, 1);
        assert_eq!(result.one_tick_input.body.policy.state.sent_heartbeats, 0);
        assert_eq!(
            result.runtime.controller.action,
            ClientHeartbeatLoopControllerAction::Sleep
        );
